import { useMemo, useState } from "react";
import PassengerSidebar from "../../components/passenger/PassengerSidebar";
import PassengerTopbar from "../../components/passenger/PassengerTopbar";
import { useAuth } from "../../context/AuthContext";
import "../../styles/auth.css";
import "../../styles/global.css";

export default function PassengerProfilePage() {
  const { user, updateUser, logout } = useAuth();
  const [editing, setEditing] = useState(false);

  const initialName =
    `${user?.firstName || ""} ${user?.lastName || ""}`.trim() ||
    user?.fullNames ||
    "";
  const [name, setName] = useState(initialName);
  const [email, setEmail] = useState(user?.email || "");
  const [phone, setPhone] = useState(user?.phone || "");

  const initials = useMemo(() => {
    if (user?.initials) return user.initials;
    const parts = (name || "").trim().split(" ").filter(Boolean);
    const first = parts[0]?.[0] || "";
    const second = parts[1]?.[0] || "";
    return `${first}${second}`.toUpperCase() || "PS";
  }, [name, user]);

  const saveProfile = () => {
    const [firstName, ...rest] = (name || "").trim().split(" ");
    const lastName = rest.join(" ");
    updateUser?.({
      firstName: firstName || "",
      lastName: lastName || "",
      fullNames: name,
      email,
      phone,
      initials,
    });
    setEditing(false);
    alert("Profile updated successfully!");
  };

  const signOut = async () => {
    const ok = window.confirm("Are you sure you want to sign out?");
    if (!ok) return;
    await logout?.();
  };

  return (
    <div className="shell">
      <PassengerSidebar />
      <div className="main">
        <PassengerTopbar
          title="My Profile"
          subtitle="Account settings and preferences"
        />

        <div className="profile-wrap">
          <section className="profile-hero">
            <div className="profile-avatar profile-avatar-lg">{initials}</div>
            <div>
              <h2>{name || "Passenger User"}</h2>
              <p>{email || "No email"}</p>
              <div className="profile-badges">
                <span
                  className={`badge ${user?.isVerified ? "badge-p" : "badge-warn"}`}
                >
                  {user?.isVerified ? "✓ Verified" : "⚠ Unverified"}
                </span>
                <span className="badge badge-info">{user?.rating ?? "—"} ★</span>
                <span className="badge badge-ok">{user?.totalTrips ?? 0} trips</span>
              </div>
            </div>
          </section>

          <section className="profile-grid">
            <article className="profile-card">
              <h3>Personal Information</h3>

              <div className="profile-item">
                <label>Full Name</label>
                {!editing ? (
                  <p>{name || "—"}</p>
                ) : (
                  <input
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    style={inputStyle}
                  />
                )}
              </div>

              <div className="profile-item">
                <label>Email Address</label>
                {!editing ? (
                  <p>{email || "—"}</p>
                ) : (
                  <input
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    style={inputStyle}
                  />
                )}
              </div>

              <div className="profile-item">
                <label>Phone Number</label>
                {!editing ? (
                  <p>{phone || "—"}</p>
                ) : (
                  <input
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    style={inputStyle}
                  />
                )}
              </div>
            </article>

            <article className="profile-card">
              <h3>Safety & Account</h3>

              <div className="profile-item">
                <label>Account Type</label>
                <p style={{ textTransform: "capitalize" }}>
                  {user?.accountType || "passenger"}
                </p>
              </div>

              <div className="profile-item">
                <label>Verification Status</label>
                <p>{user?.isVerified ? "Verified" : "Not verified yet"}</p>
              </div>

              <div className="profile-item">
                <label>Total Trips</label>
                <p>{user?.totalTrips ?? 0}</p>
              </div>
            </article>
          </section>

          <section className="profile-actions">
            {!editing ? (
              <button
                className="btn-primary"
                type="button"
                onClick={() => setEditing(true)}
              >
                Edit Profile
              </button>
            ) : (
              <>
                <button
                  className="btn btn-outline"
                  type="button"
                  onClick={() => setEditing(false)}
                >
                  Cancel
                </button>
                <button className="btn btn-p" type="button" onClick={saveProfile}>
                  Save Changes
                </button>
              </>
            )}

            <button className="btn btn-danger" type="button" onClick={signOut}>
              Sign Out
            </button>
          </section>
        </div>
      </div>
    </div>
  );
}

const inputStyle = {
  width: "100%",
  background: "#F9FAFB",
  border: "1px solid #D0D5DD",
  borderRadius: 10,
  padding: "10px 12px",
  color: "#101828",
  fontSize: 14,
  outline: "none",
};
